@page "/category/{CategoryName}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@CategoryName Recipes — RecipeShare</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>
    @(CategoryName switch
    {
        "Italian" => "🍝",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Asian" => "🥢",
        "Desserts" => "🍰",
        _ => "🍽️"
    })
    @CategoryName Recipes
</h1>

@if (recipes.Count == 0)
{
    <div class="alert alert-info">No recipes found in this category.</div>
}
else
{
    <div class="row g-4 mt-2">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">@recipe.Description</p>
                        <div class="d-flex justify-content-between align-items-center">
                            <span class="text-warning">
                                @for (int i = 1; i <= 5; i++)
                                {
                                    @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                                }
                                <small class="text-muted ms-1">(@recipe.TotalRatings)</small>
                            </span>
                            <a href="recipe/@recipe.Id" class="btn btn-outline-primary btn-sm">View Recipe</a>
                        </div>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = "";

    private IReadOnlyList<RecipeShare.Services.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{RecipeId:int}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") — RecipeShare</PageTitle>

@if (recipe is null)
{
    <div class="alert alert-warning">Recipe not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="category/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="lead text-muted">@recipe.Description</p>

    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />

    <div class="row mt-4">
        <div class="col-md-4">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">🧾 Ingredients</h5></div>
                <ul class="list-group list-group-flush">
                    @foreach (var ingredient in recipe.Ingredients)
                    {
                        <li class="list-group-item">@ingredient</li>
                    }
                </ul>
            </div>
        </div>

        <div class="col-md-8">
            <div class="card">
                <div class="card-header"><h5 class="mb-0">👨‍🍳 Instructions</h5></div>
                <div class="card-body">
                    <ol class="mb-0">
                        @foreach (var step in recipe.Steps)
                        {
                            <li class="mb-2">@step</li>
                        }
                    </ol>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int RecipeId { get; set; }

    private RecipeShare.Services.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(RecipeId);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="my-3 p-3 border rounded bg-light">
    <div class="d-flex align-items-center gap-3">
        <span class="fw-bold">Rate this recipe:</span>
        <span class="star-rating">
            @for (int i = 1; i <= 5; i++)
            {
                var star = i;
                <span class="star @(star <= hoverRating ? "star-hover" : star <= currentRating ? "star-selected" : "")"
                      @onclick="() => SubmitRating(star)"
                      @onmouseover="() => hoverRating = star"
                      @onmouseout="() => hoverRating = 0"
                      role="button"
                      title="@star star(s)">
                    @(star <= (hoverRating > 0 ? hoverRating : currentRating) ? "★" : "☆")
                </span>
            }
        </span>
        @if (submitted)
        {
            <span class="text-success fw-bold">✓ Thanks for rating!</span>
        }
    </div>
    @if (recipe is not null)
    {
        <small class="text-muted mt-1 d-block">
            Average: @recipe.AverageRating.ToString("F1") / 5 (@recipe.TotalRatings ratings)
        </small>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private RecipeShare.Services.Recipe? recipe;
    private int currentRating;
    private int hoverRating;
    private bool submitted;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetById(RecipeId);
    }

    private void SubmitRating(int stars)
    {
        currentRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        recipe = RecipeService.GetById(RecipeId);
        submitted = true;
    }
}

