    cursor: pointer;
}

.category-card:hover {
    transform: translateY(-4px);
    box-shadow: 0 6px 20px rgba(0,0,0,0.15) !important;
}

.category-card h2 {
    font-size: 3rem;
}

.star-rating .star {
    font-size: 1.8rem;
    cursor: pointer;
    color: #ccc;
    transition: color 0.15s;
    user-select: none;
}

.star-rating .star-selected {
    color: #ffc107;
}

.star-rating .star-hover {
    color: #ffca2c;
}

